const Text = () => {
  const [enable, setEnable] = useState(true);
  const [time, setTime] = useState(0);
  const animate = useAnimationFunction(
    ({ progress }) => {
      setTime(progress);
    },
    {
      duration: 1000,
      easing: "ease-in-out",
      iterations: Infinity,
      direction: "alternate",
    }
  );

  useEffect(() => {
    animate.play();
  }, [animate]);

  const onClick = useCallback(() => {
    setEnable((p) => !p);
    if (enable) {
      animate.pause();
    } else {
      animate.play();
    }
  }, [animate, enable]);

  return (
    <div>
      <button onClick={onClick}>{enable ? "stop" : "start"}</button>
      <div>{time.toFixed(6)}</div>
    </div>
  );
};

const Progress = () => {
  const [value, setValue] = useState(0);
  const animate = useAnimationFunction<{ start: number; end: number }>(
    ({ progress }, arg) => {
      setValue(arg.start * (1 - progress) + progress * arg.end);
    },
    {
      duration: 600,
      easing: "ease-in-out",
    }
  );
  useEffect(() => {
    animate.play({ args: { start: value, end: Math.random() * 100 } });
  }, []);

  return (
    <>
      <div>
        <progress value={value} max={100} style={{ width: 600 }} />
      </div>
      <div>
        <button
          onClick={() => animate.play({ args: { start: value, end: 0 } })}
        >
          0%
        </button>
        <button
          onClick={() => animate.play({ args: { start: value, end: 50 } })}
        >
          50%
        </button>
        <button
          onClick={() => animate.play({ args: { start: value, end: 100 } })}
        >
          100%
        </button>
      </div>
    </>
  );
};

const Canvas = () => {
  const ref = useRef<HTMLCanvasElement>(null);
  const ctxRef = useRef<CanvasRenderingContext2D | null>(null);
  const width = 400;
  const height = 400;
  const animate = useAnimationFunction(
    (timing) => {
      if (!ref.current) return;
      const ctx =
        ctxRef.current || (ctxRef.current = ref.current.getContext("2d")!);
      ctx.clearRect(0, 0, width, height);
      const fillStyle = ["red", "blue", "green"][timing.currentIteration % 3];
      ctx.fillStyle = fillStyle;
      ctx.font = ctx.font.replace(
        /\d+px/,
        `${Math.floor(timing.progress * 50)}px`
      );
      ctx.fillText(fillStyle, 40, 80);
      ctx.beginPath();
      ctx.arc(width / 2, height / 2, 50 * timing.progress, 0, Math.PI * 2);
      ctx.fill();
    },
    {
      easing: "ease-in-out",
      duration: 1000,
      iterations: Infinity,
    }
  );

  useEffect(() => {
    animate.play();
  }, [animate]);

  return <canvas ref={ref} width={width} height={height} />;
};

