          play: (...opts) => {
            const animation = init(((opts[0] || {}) as { args?: Args }).args!);
            if (animation) {
              _play(animation);
            }
            return externalHandle;
          },
          reverse: () => {
            const animation = currentAnimation();
            if (animation) {
              _reverse(animation);
            }
            return externalHandle;
          },
          cancel: () => {
