import type {
  TypedKeyframeEffectOptions,
  GetKeyframeFunction,
  TypedKeyframe,
} from "../../core/index.js";
import { useStatic } from "./useStatic.js";
import { useLatestRef } from "./useLatestRef.js";

export interface TransitionAnimationHandle {
  (ref: Element | null): void;
