            return externalHandle;
          },
          finish: () => {
            const animation = currentAnimation();
            if (animation) {
              _finish(animation);
            }
            return externalHandle;
          },
          pause: () => {
            const animation = currentAnimation();
            if (animation) {
              _pause(animation);
            }
            return externalHandle;
          },
          setTime: (time) => {
            let animation = currentAnimation();
            if (!animation) {
