const Default = () => {
  const animate = useAnimation(
    [
      { transform: "rotate(0deg)", borderRadius: "1rem" },
      { transform: "rotate(360deg)", borderRadius: "50%" },
      { transform: "rotate(720deg)", borderRadius: "1rem" },
    ],
    {
      duration: 1000,
      iterations: Infinity,
      easing: "ease-in-out",
    }
  );

  useEffect(() => {
    animate.play();
  }, []);

  return (
    <Comp
      ref={animate}
      onMouseEnter={() => {
        animate.pause();
      }}
      onMouseLeave={() => {
        animate.play();
      }}
    />
  );
};

